package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetAllowMissingColumnNames() {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Set the expected value for allowMissingColumnNames
        boolean expected = true;

        // Mock the behavior of getAllowMissingColumnNames() to return the expected value
        when(csvFormat.getAllowMissingColumnNames()).thenReturn(expected);

        // Call the method under test
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Verify the result
        assertEquals(expected, result);
    }
}
